                const newMask = mask | (1 << neighbor);
                const newStr = currentStr + label[neighbor];
                queue.push([neighbor, newMask, newStr]);
            }
        }
    }

    return maxLen;
}

function isPalindrome(s) {
    let left = 0;
    let right = s.length - 1;
    while (left < right) {
        if (s[left] !== s[right]) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}
