function solve(n, edges, label) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 1; // At least one character can form a palindrome

    // We'll use BFS with a state that includes the current node and a frequency map
    // Since n is small (<=14), we can represent the visited nodes as a bitmask
    const queue = [];

    // Initialize queue with all possible starting nodes and their initial state
    for (let i = 0; i < n; i++) {
        const mask = 1 << i;
        const freq = new Array(26).fill(0);
        freq[label.charCodeAt(i) - 97] += 1;
        queue.push({ node: i, mask, freq });
    }

    while (queue.length > 0) {
        const { node, mask, freq } = queue.shift();

        // Check if current path can form a palindrome
        let oddCount = 0;
        let total = 0;
        for (const count of freq) {
            if (count % 2 !== 0) {
                oddCount++;
            }
            total += count;
        }
        if (oddCount <= 1 && total > maxLen) {
            maxLen = total;
        }

        // Explore neighbors
        for (const neighbor of adj[node]) {
            if (!(mask & (1 << neighbor))) {
                const newMask = mask | (1 << neighbor);
                const newFreq = [...freq];
                newFreq[label.charCodeAt(neighbor) - 97] += 1;
                queue.push({ node: neighbor, mask: newMask, freq: newFreq });
            }
        }
    }

    return maxLen;
}
